import React from 'react';
import { Navigate, Route, Routes } from 'react-router-dom';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import CarDetailPage from './pages/CarDetailPage';
import CustomerBookingsPage from './pages/CustomerBookingsPage';
import MyProfilePage from './pages/MyProfilePage';
import AdminDashboard from './pages/AdminDashboard';
import AllBookingsAdminPage from './pages/AllBookingsAdminPage';
import AddCompanyPage from './pages/AddCompanyPage';
import AddVariantPage from './pages/AddVariantPage';
import AllVariantsPage from './pages/AllVariantsPage';
import CustomersPage from './pages/CustomersPage';
import { getRole, isLoggedIn } from './services/authService';

function ProtectedRoute({ children, role }) {
  if (!isLoggedIn()) {
    return <Navigate to="/login" replace />;
  }

  if (role && getRole() !== role) {
    return <Navigate to="/" replace />;
  }

  return children;
}

export default function App() {
  return (
    <Routes>
      <Route path="/" element={<HomePage />} />
      <Route path="/login" element={<LoginPage />} />
      <Route path="/register" element={<RegisterPage />} />
      <Route path="/car/detail/:id" element={<CarDetailPage />} />
      <Route
        path="/customer/bookings"
        element={
          <ProtectedRoute role="CUSTOMER">
            <CustomerBookingsPage />
          </ProtectedRoute>
        }
      />
      <Route
        path="/customer/profile"
        element={
          <ProtectedRoute role="CUSTOMER">
            <MyProfilePage />
          </ProtectedRoute>
        }
      />
      <Route
        path="/admin/dashboard"
        element={
          <ProtectedRoute role="ADMIN">
            <AdminDashboard />
          </ProtectedRoute>
        }
      />
      <Route
        path="/admin/bookings"
        element={
          <ProtectedRoute role="ADMIN">
            <AllBookingsAdminPage />
          </ProtectedRoute>
        }
      />
      <Route
        path="/admin/add-company"
        element={
          <ProtectedRoute role="ADMIN">
            <AddCompanyPage />
          </ProtectedRoute>
        }
      />
      <Route
        path="/admin/add-variant"
        element={
          <ProtectedRoute role="ADMIN">
            <AddVariantPage />
          </ProtectedRoute>
        }
      />
      <Route
        path="/admin/variants"
        element={
          <ProtectedRoute role="ADMIN">
            <AllVariantsPage />
          </ProtectedRoute>
        }
      />
      <Route
        path="/admin/customers"
        element={
          <ProtectedRoute role="ADMIN">
            <CustomersPage />
          </ProtectedRoute>
        }
      />
    </Routes>
  );
}
